<script setup lang="ts">import { computed, ref, watch } from 'vue'; import { dashboard } from '../api'; import { useAsyncData } from '../composables/useAsyncData'; import { useAutoRefresh } from '../composables/useAutoRefresh'; import AppShell from '../components/AppShell.vue'; import AsyncPanel from '../components/AsyncPanel.vue'; import HoursSelect from '../components/HoursSelect.vue'; const hours=ref(24); const state=useAsyncData(async()=>(await dashboard.usage(hours.value)).items); const groups=computed(()=>['instance_user','instance_channel','instance_model'].map((type,i)=>({title:['客户排行','渠道排行','模型排行'][i],items:(state.data.value||[]).filter(x=>x.dimension_type===type).slice(0,20)}))); watch(hours,()=>void state.reload()); useAutoRefresh(state.reload);</script>
<template><AppShell title="用量统计"><div class="panel-title"><p class="hint">用量契约不支持 instance_id，本页展示全部实例聚合。</p><HoursSelect v-model="hours" :options="[24,72,168]"/></div><AsyncPanel :loading="state.loading.value" :error="state.error.value" :empty="!state.data.value?.length" @retry="state.reload"><div class="usage-grid"><section v-for="group in groups" :key="group.title" class="panel"><h2>{{group.title}}</h2><el-table :data="group.items"><el-table-column prop="display_key" label="名称"/><el-table-column prop="request_count" label="请求"/><el-table-column prop="prompt_tokens" label="Token In"/><el-table-column prop="completion_tokens" label="Token Out"/><el-table-column prop="quota" label="Quota"/></el-table></section></div></AsyncPanel></AppShell></template>
